sys_script_fix.script:
(function() {
    var BATCH_SIZE = 1;
    var cancelledCount = 0;
    var wf = new Workflow();

    var sysIdList = [];
    var grCustom = new GlideRecord('u_wf_context_case');
    grCustom.addEncodedQuery("wf_sys_id=09ca4299479392101065fa57436d43ba");
    grCustom.query();
    while (grCustom.next() && sysIdList.length < BATCH_SIZE) {
        sysIdList.push(grCustom.wf_sys_id.toString());
    }
    if (sysIdList.length === 0) {
        gs.info("No workflow contexts found to cancel in this run.");
        return;
    }
    var gr_wf = new GlideRecord('wf_context');
    gr_wf.addQuery('sys_id', 'IN', sysIdList);
    gr_wf.query();
    while (gr_wf.next()) {
        try {
            gr_wf.setWorkflow(false);
            gr_wf.autoSysFields(false);
            wf.cancelContext(gr_wf);
            cancelledCount++;
        } catch (ex) {
            gs.error("Error cancelling workflow context " + gr_wf.sys_id + ": " + ex.message);
        }
    }
    gs.info("Workflows cancelled this run: " + cancelledCount);
})();
